def buildAdjustment(raw) {
  return {
    amount: raw.discount
  };
}

val raw = {
  price: "50",
  discount: "8"
};

val adjustment = buildAdjustment(raw);
val price = parseNumber(raw.price);
val discount = parseNumber(adjustment.amount);
val final = price - discount;

print(final);
